import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import './ProfilePage.css';

const tabs = [
  { id: 'overview', label: 'Overview', icon: 'fa-home' },
  { id: 'activity', label: 'Activity', icon: 'fa-chart-line' },
  { id: 'library', label: 'Library', icon: 'fa-book' },
  { id: 'reviews', label: 'Reviews', icon: 'fa-star' },
  { id: 'settings', label: 'Settings', icon: 'fa-cog' }
];

const ProfilePage = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');
  const [isEditing, setIsEditing] = useState(false);
  const [profileData, setProfileData] = useState({
    username: user?.username || '',
    email: user?.email || '',
    bio: 'Manga and anime fan. Reading every day.',
    avatar: null
  });

  useEffect(() => {
    if (!user) return;
    const stored = localStorage.getItem(`mangauz_profile_${user.id}`);
    if (stored) {
      setProfileData(JSON.parse(stored));
    }
  }, [user]);

  const handleSave = () => {
    if (!user) return;
    localStorage.setItem(`mangauz_profile_${user.id}`, JSON.stringify(profileData));
    setIsEditing(false);
  };

  if (!user) {
    return (
      <div className="profile-page">
        <div className="not-logged-in">
          <h2>Please sign in</h2>
          <p>You need to login to view this page.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="profile-page">
      <div className="profile-header">
        <div className="profile-cover">
          <div className="cover-overlay"></div>
        </div>

        <div className="profile-info">
          <div className="avatar-section">
            <div className="avatar-container">
              <div className="avatar">
                {user.avatar ? <img src={user.avatar} alt={user.username} /> : <i className="fas fa-user"></i>}
              </div>
              <div className="level-badge">Level {user.level}</div>
            </div>
            <div className="profile-stats">
              <div className="stat">
                <span className="stat-value">{user.points}</span>
                <span className="stat-label">Points</span>
              </div>
              <div className="stat">
                <span className="stat-value">245</span>
                <span className="stat-label">Read</span>
              </div>
              <div className="stat">
                <span className="stat-value">89</span>
                <span className="stat-label">Reviews</span>
              </div>
            </div>
          </div>

          <div className="profile-details">
            <div className="profile-header-row">
              {isEditing ? (
                <input
                  type="text"
                  value={profileData.username}
                  onChange={(e) => setProfileData({ ...profileData, username: e.target.value })}
                  className="username-input"
                />
              ) : (
                <h1 className="username">{profileData.username || user.username}</h1>
              )}

              {isEditing ? (
                <div className="edit-buttons">
                  <button className="save-btn" onClick={handleSave}>Save</button>
                  <button className="cancel-btn" onClick={() => setIsEditing(false)}>Cancel</button>
                </div>
              ) : (
                <button className="edit-btn" onClick={() => setIsEditing(true)}>
                  <i className="fas fa-edit"></i>
                  Edit profile
                </button>
              )}
            </div>

            <div className="profile-meta">
              <span className="meta-item">
                <i className="fas fa-envelope"></i>
                {isEditing ? (
                  <input
                    type="email"
                    value={profileData.email}
                    onChange={(e) => setProfileData({ ...profileData, email: e.target.value })}
                    className="email-input"
                  />
                ) : (
                  profileData.email || user.email
                )}
              </span>
              <span className="meta-item"><i className="fas fa-calendar"></i>Member since Jan 2023</span>
              <span className="meta-item"><i className="fas fa-clock"></i>Active 2 hours ago</span>
            </div>

            <div className="profile-bio">
              <h3>About</h3>
              {isEditing ? (
                <textarea
                  value={profileData.bio}
                  onChange={(e) => setProfileData({ ...profileData, bio: e.target.value })}
                  className="bio-input"
                  rows="4"
                />
              ) : (
                <p>{profileData.bio}</p>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="profile-tabs">
        <div className="tabs-nav">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              className={`tab-btn ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <i className={`fas ${tab.icon}`}></i>
              {tab.label}
            </button>
          ))}
        </div>

        <div className="tab-content">
          {activeTab === 'overview' && (
            <div className="overview-tab">
              <div className="recent-activity">
                <h3>Recent activity</h3>
                <div className="activity-list">
                  {[
                    { action: 'Read chapter', title: 'Berserk #363', time: '2 hours ago' },
                    { action: 'Posted review', title: 'Solo Leveling', time: '5 hours ago' },
                    { action: 'Added to library', title: 'Tower of God', time: '1 day ago' }
                  ].map((activity, index) => (
                    <div key={index} className="activity-item">
                      <div className="activity-icon"><i className="fas fa-bolt"></i></div>
                      <div className="activity-info">
                        <span className="activity-action">{activity.action}</span>
                        <span className="activity-title">{activity.title}</span>
                      </div>
                      <span className="activity-time">{activity.time}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'activity' && (
            <div className="library-tab">
              <h3>Activity feed</h3>
              <p>Detailed history of your interactions on the platform.</p>
              <div className="activity-list">
                {['Liked a review', 'Followed a user', 'Completed 5 chapters'].map((item, i) => (
                  <div key={i} className="activity-item">
                    <div className="activity-icon"><i className="fas fa-history"></i></div>
                    <div className="activity-info"><span className="activity-action">{item}</span></div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'library' && (
            <div className="library-tab">
              <h3>My library</h3>
              <p>Berserk, Solo Leveling, Tower of God, Attack on Titan</p>
            </div>
          )}

          {activeTab === 'reviews' && (
            <div className="library-tab">
              <h3>My reviews</h3>
              <p>You have written 2 reviews this month.</p>
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="settings-tab">
              <h3>Settings</h3>
              <p>Edit and save your profile data from this page.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;
